            for pkg in fw.get('topLevelPackages', []):
                key = (name, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = pkg_map(baseline)
a = pkg_map(after)

changes = []
unchanged = []
all_keys = sorted(set(b.keys()) | set(a.keys()))
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        changes.append((k[0], k[1], k[2], bv or 'N/A', av or 'N/A'))
    else:
        unchanged.append((k[0], k[1], k[2], bv))

if changes:
    print('CHANGES:')
    for c in changes:
        print(f'  {c[0]} ({c[1]}): {c[2]}  {c[3]} -> {c[4]}')
else:
    print('NO CHANGES - fully version-neutral')

print(f'\nTotal unchanged: {len(unchanged)}')
print(f'Total changed: {len(changes)}')
PYEOF
